"""
MKT Christ Commentary — 2 Chronicles chapters 18–20
Run: python3 scripts/zc-christ-2chronicles-18-20.py

Ch 18: Micaiah vs. 400 false prophets — the true voice vs. false:
  - v7-8: Micaiah hated/rejected → type: prophet rejected as Christ was
  - v12-13: "I will speak only what my God tells me" → type: Christ's words from the Father
  - v16: "sheep without a shepherd" → direct: Matt 9:36 / Mark 6:34 — Jesus quotes/echoes this
  - v18-22: The heavenly throne-room vision → revelation of God: divine governance (cf. Rev 4-5)
  - v23-24: Micaiah struck → type: the prophet struck as Christ was
  - v31: Jehoshaphat cries out → shadow: prayer averts judgment on the covenant people
  - v33-34: Arrow without aim kills Ahab → revelation of God: sovereign judgment finds its target

Ch 19: Jehoshaphat's judicial reform — impartial divine justice:
  - v3-4: "some good in you" + goes to bring people back → type: shepherd-king seeking the lost
  - v5-7: "you are not judging for human beings but for the LORD" → direct: all judgment before God
  - v6: "no injustice, favoritism, or bribery" → revelation of God: basis of NT impartiality texts
  - v8-11: Dual priestly-civic authority → shadow: Christ unifying both in Melchizedek pattern

Ch 20: Jehoshaphat's battle — the paradigmatic "battle is God's" victory:
  - v12: "we do not know what to do, but our eyes are on you" → direct: Gethsemane posture
  - v14-17: "the battle is not yours but God's" → direct: the war Christ fights for us (Col 2:15)
  - v15: "do not be afraid" + "the battle is God's" → direct: John 16:33 / Eph 6:10-13
  - v21-22: Praise precedes the victory ambush → type: the cross as God's hidden ambush (1 Cor 1:18-25)
  - v30: Rest on every side → shadow: the Sabbath rest Christ brings (Heb 4:1-11)
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

CHRIST = {
  "18": {
    "1": "<p>A shadow. Jehoshaphat&rsquo;s great wealth and honor — the height of his covenant blessing — becomes the occasion for the alliance with Ahab that nearly kills him. Prosperity without discernment creates the conditions for compromise. The pattern recurs throughout Scripture: God&rsquo;s blessings (position, resources, relationships) can become leverage points for enemy alliances. Christ reverses this: he took on poverty and vulnerability so that we might be enriched without the entanglements that wealth produces (2 Cor 8:9).</p>",
    "2": "<p>A shadow. Ahab&rsquo;s lavish feast for Jehoshaphat — great numbers of sheep and cattle slaughtered to entertain the king of Judah — represents the seductive hospitality of worldly alliance. The appeal of Ahab&rsquo;s court (great wealth, military power, cultural sophistication) mirrors every generation&rsquo;s temptation to be drawn into the orbit of the powerful at the cost of covenant distinctiveness. The banquet that becomes the prelude to spiritual compromise is reversed in Christ&rsquo;s table, where the feast is given by the one who does not exploit the guest.</p>",
    "3": "<p>A shadow. &lsquo;I am with you, and my people are your people&rsquo; — Jehoshaphat&rsquo;s full identification with Ahab&rsquo;s cause is the language of covenant loyalty (&lsquo;your people are my people&rsquo; echoes Ruth 1:16) applied to an ungodly alliance. The covenant formula of solidarity, properly used for YHWH-partnerships, is here misapplied to a partnership with the wicked. Christ is the one who rightly speaks this formula: he identified fully with his people, taking their cause as his own — not compromising the covenant but fulfilling it (John 17:21-23: &lsquo;that they may be one, even as we are one&rsquo;).</p>",
    "4": "<p>A theme. Jehoshaphat&rsquo;s insistence on seeking the word of the LORD before battle — even within an already-compromised alliance — is the one right instinct in a wrong situation. The discipline of seeking divine guidance before action, whatever the surrounding circumstances, is the prophetic-covenant posture. Christ embodies this perfectly: before every major decision, he withdrew to pray (Luke 5:16; 6:12; 9:18; 22:41). The seeker of YHWH&rsquo;s word amidst ungodly alliances is the type of the one who only does what he sees the Father doing (John 5:19).</p>",
    "5": "<p>A type. The four hundred prophets who unanimously declare what the kings want to hear represent the false prophetic consensus that tells power what power wants. The pattern Jesus warns against: &lsquo;Woe to you when all people speak well of you, for so their fathers did to the false prophets&rsquo; (Luke 6:26). Paul warns the same: &lsquo;the time will come when people will not endure sound teaching, but having itching ears they will accumulate for themselves teachers to suit their own passions&rsquo; (2 Tim 4:3). The 400 false voices vs. one true voice anticipates the minority-truth pattern of genuine prophetic witness.</p>",
    "6": "<p>A type. Jehoshaphat&rsquo;s question — &lsquo;Is there another prophet of the LORD here we could consult?&rsquo; — is the discerning ear that notices the absence of authentic divine speech even amidst the noise of four hundred voices. The ability to sense that the unanimously affirming voices are not the voice of YHWH is a mark of covenant attentiveness. Hebrews 5:14 describes the mature as those &lsquo;who have their powers of discernment trained by constant practice to distinguish good from evil.&rsquo; The seeker of the true word points toward those in every generation who, despite the pressure of consensus, ask: &lsquo;is there yet another word from the LORD?&rsquo;</p>",
    "7": "<p>A type. Ahab&rsquo;s admission that he hates Micaiah &lsquo;because he never prophesies good about me, only disaster&rsquo; is the purest expression of the false-prophet preference: truth is measured by its palatability. The same complaint was made about Jeremiah (Jer 20:8: &lsquo;the word of YHWH has become for me a reproach and derision all day long&rsquo;) and about Jesus (John 7:7: &lsquo;the world... hates me because I testify about it that its works are evil&rsquo;). The hated prophet is the type of the one whose words diagnose the condition the hearer most wants to avoid hearing.</p>",
    "8": "<p>A shadow. The officer sent to summon Micaiah &lsquo;immediately&rsquo; — on the king&rsquo;s urgent command — brings the prophet into the hostile context where truth will be tested. The summons of the true prophet into a hostile royal court is the recurring pattern of prophetic ministry: Elijah before Ahab (1 Kgs 18:17), Jeremiah before Jehoiakim (Jer 36), Jesus before the Sanhedrin and Pilate. The prophet who comes when called, knowing the cost, shadows the obedience of Christ who did not flee the summons to the cross (Matt 26:63-64: before the high priest, Jesus did not remain silent).</p>",
    "9": "<p>A revelation of God. The two kings on their thrones in royal robes at the threshing floor of the gate — the ceremonial display of human royal power — frames the scene that Micaiah&rsquo;s vision will subvert. Against these two earthly thrones, Micaiah will describe a heavenly throne (v18) that renders all earthly royal display trivially provisional. The contrast between the threshing-floor thrones and the heavenly throne is the OT&rsquo;s version of Rev 4:2-3: the thrones of Revelation&rsquo;s human powers exist only in the context of the one heavenly throne before which all others give way.</p>",
    "10": "<p>A type. Zedekiah&rsquo;s iron horns as a physical sign authenticating his false prophecy represent the false-sign pattern that Jesus warns against: &lsquo;false christs and false prophets will arise and perform great signs and wonders, so as to lead astray, if possible, even the elect&rsquo; (Matt 24:24). The sign made by human hands — iron horns Zedekiah made &lsquo;for himself&rsquo; (<em>lô</em> — made himself the prophet-actor) — contrasts with genuine signs that come from divine initiative. The theatrical performance of prophetic authority without divine commission is the type of every false spiritual leader.</p>",
    "11": "<p>A shadow. The false prophetic consensus — &lsquo;march on Ramoth-gilead and be victorious, for the LORD will give it into the king&rsquo;s hand&rsquo; — is a shadow of the false assurance of every generation that promises divine blessing on human schemes. The word &lsquo;victorious&rsquo; without the obedient heart that produces it is the essence of presumption. Christ confronts this presumption: when Satan quotes Scripture to promise him protection in a temple jump (Matt 4:6-7), Jesus refuses the false assurance — &lsquo;you shall not put the Lord your God to the test.&rsquo; The true word of God cannot be commandeered for human ambition.</p>",
    "12": "<p>A type. The messenger who coached Micaiah to conform his word to the royal consensus — &lsquo;all the prophets are speaking favorably; your word should be like theirs and you should speak favorably&rsquo; — is the pressure every true witness faces to adjust the message to the audience&rsquo;s preference. Gal 1:10: &lsquo;For am I now seeking the approval of man, or of God? Or am I trying to please man? If I were still trying to please man, I would not be a servant of Christ.&rsquo; Paul&rsquo;s apostolic independence from the approval-seeking that the messenger demanded of Micaiah is the Christ-shaped posture that refuses accommodation.</p>",
    "13": "<p>A direct connection. Micaiah&rsquo;s oath — &lsquo;As the LORD lives, I will speak only what my God tells me&rsquo; — is the OT&rsquo;s clearest statement of the prophetic-messenger principle. Jesus embodies this principle absolutely: &lsquo;I have not spoken on my own authority; the Father who sent me has himself given me a commandment — what to say and what to speak. And I know that his commandment is eternal life. What I say, therefore, I say as the Father has told me&rsquo; (John 12:49-50). Micaiah speaks only YHWH&rsquo;s word; Christ speaks only the Father&rsquo;s word — the prophet&rsquo;s principle fulfilled in the incarnate Word.</p>",
    "14": "<p>A type. Micaiah&rsquo;s initial ironic agreement — &lsquo;march on, be victorious, and they will be given into your hand&rsquo; — which Ahab immediately recognizes as false (v15) is a testing utterance: it reveals whether the king seeks YHWH&rsquo;s genuine word or wants religious confirmation of his predetermined plan. Jesus similarly tests questioners: to the rich young ruler who asked what to do to inherit eternal life, Jesus&rsquo; full answer probed whether the man wanted the truth or wanted validation (Matt 19:16-22). The ironic first response reveals the heart&rsquo;s posture toward the genuine prophetic word.</p>",
    "15": "<p>A shadow. The king&rsquo;s insistence that Micaiah swear to tell only truth — &lsquo;how many times must I make you swear to tell me only the truth in the LORD&rsquo;s name?&rsquo; — while simultaneously being unwilling to act on the truth he receives, is the type of hearing without obedience. The person who demands the truth but will not be changed by it is described in Matt 7:24-27 (the two builders): hearing without doing is building on sand. The king who asks for the word but ignores it proceeds to his death exactly as the word predicted. The unteachable hearer is a repeated NT warning.</p>",
    "16": "<p>A direct connection. Micaiah&rsquo;s vision of Israel scattered over the mountains like sheep without a shepherd is one of the OT&rsquo;s most poignant images of covenant abandonment. Jesus explicitly draws on this image in Matt 9:36: &lsquo;When he saw the crowds, he had compassion on them, because they were harassed and helpless, like sheep without a shepherd.&rsquo; Mark 6:34 uses it again. The image Micaiah used to describe Israel&rsquo;s condition after Ahab&rsquo;s death becomes Jesus&rsquo; description of the condition of Israel under Second Temple leadership — and the motive for his own shepherding ministry. The Good Shepherd (John 10:11-16) comes precisely to gather the scattered sheep.</p>",
    "17": "<p>A shadow. The king&rsquo;s bitter recognition — &lsquo;didn&rsquo;t I tell you? He never prophesies good about me, only disaster&rsquo; — is the shadow of every generation&rsquo;s complaint against the word of God that brings conviction rather than comfort. The true word is often first received as unwelcome news before its merciful purpose is understood. Jesus&rsquo; words were similarly received: &lsquo;this is a hard saying; who can listen to it?&rsquo; (John 6:60). The king who identifies truth-telling with disaster-bringing has inverted the categories: the prophet&rsquo;s difficult word was the mercy that could have saved him.</p>",
    "18": "<p>A revelation of God. Micaiah&rsquo;s throne-room vision — &lsquo;I saw the LORD enthroned, with all the heavenly host standing on his right and on his left&rsquo; — is one of the OT&rsquo;s great apocalyptic glimpses of the divine governing council. The same throne-room tradition appears in Isa 6:1-8 (Isaiah sees YHWH enthroned), Dan 7:9-10 (the Ancient of Days seated), and culminates in Rev 4:2-11. In this tradition, the events of human history are governed from the heavenly throne room. Christ is the Lamb who stands at the center of this throne (Rev 5:6: &lsquo;a Lamb standing, as though it had been slain, in the midst of the throne and the four living creatures&rsquo;), the one through whom the divine governance is now disclosed.</p>",
    "19": "<p>A revelation of God. YHWH&rsquo;s question to the heavenly council — &lsquo;Who will lure Ahab... so he will fall there?&rsquo; — reveals divine governance working through secondary causes to accomplish judgment. The voluntary participation of spiritual beings in divine judgment-plans is the backdrop for NT passages about spiritual warfare and divine permission (Job 1-2: YHWH permits the adversary&rsquo;s work; 2 Thess 2:11: God sends a strong delusion; Rev 20:7: YHWH releases Satan for the final conflict). The hardening-for-judgment principle that governs Pharaoh (Exod 4:21; Rom 9:17-18) is here extended to Ahab through the divine council&rsquo;s instrumentality.</p>",
    "20": "<p>A revelation of God. The spirit&rsquo;s volunteering — &lsquo;I will entice him&rsquo; — and YHWH&rsquo;s authorization — &lsquo;you will succeed; go and do it&rsquo; — is the OT&rsquo;s most explicit picture of divine governance using deception for judgment purposes. This is not deception of the innocent but confirmation of a king already committed to unbelief. Paul draws on the same principle in 2 Thess 2:11-12: &lsquo;God sends them a strong delusion, so that they may believe what is false, in order that all may be condemned who did not believe the truth but had pleasure in unrighteousness.&rsquo; The God who governs all things is sovereign even over the lying voices people choose to hear.</p>",
    "21": "<p>A revelation of God. The lying spirit in the mouths of all four hundred prophets — a single spiritual cause producing unanimous false prophecy — reveals the spiritual-warfare reality behind prophetic consensus. Paul warns: &lsquo;even Satan disguises himself as an angel of light. So it is no surprise if his servants also disguise themselves as servants of righteousness&rsquo; (2 Cor 11:14-15). The unanimous certainty of 400 voices is not self-authenticating; spiritual unanimity can serve either truth or deception. The test of the true word is not its popularity or the number of its advocates but its conformity to YHWH&rsquo;s revealed character.</p>",
    "22": "<p>A revelation of God. &lsquo;The LORD has put a lying spirit in the mouths of your prophets, and the LORD has decreed disaster for you&rsquo; — the prophet who can see the spiritual mechanism behind the false prophetic consensus is the rare servant of God who perceives how divine judgment uses the very sins of the people (appetite for flattering prophecy) as the instrument of their destruction. Christ is the one who sees through all deception (John 2:24-25: &lsquo;he knew what was in man&rsquo;) and speaks the truth even when it leads to his death. The true prophet&rsquo;s word, spoken into the lying consensus, is itself an act of resistance to the judgment-mechanism that silence would accelerate.</p>",
    "23": "<p>A type. Zedekiah&rsquo;s slap and mockery — &lsquo;Which way did the Spirit of YHWH go when he left me to speak to you?&rsquo; — is the physical attack on the true prophet by the false prophet, combining violence with theological contempt. The pattern is fulfilled in the passion: Jesus was struck and mocked with the challenge to prophecy (Matt 26:67-68: &lsquo;they slapped him, saying, &ldquo;Prophesy to us, Christ! Who is it that struck you?&rdquo;&rsquo;). The contemptuous questioning of authentic prophetic identity — &lsquo;prove which Spirit speaks through you&rsquo; — is the enduring taunt against every true witness.</p>",
    "24": "<p>A type. Micaiah&rsquo;s calm prophecy against Zedekiah — &lsquo;you will find out on the day you go into an inner room to hide&rsquo; — is the composed confidence of the true prophet in the face of violence. No defense, no retaliation, only the word of coming vindication. Jesus before his accusers: &lsquo;you will see the Son of Man seated at the right hand of Power and coming on the clouds of heaven&rsquo; (Matt 26:64). The true prophet and the Son of Man share the same composure before violence: vindication is certain and near; present suffering does not need to be defended against.</p>",
    "25": "<p>A shadow. The imprisoned Micaiah — placed under guard, on reduced bread and water, awaiting what the king determines — is the type of the faithful witness imprisoned by power. The OT&rsquo;s imprisoned prophets (Jeremiah in the cistern, Jer 38; Joseph in prison, Gen 39; Daniel) form the chain of imprisoned witnesses that reaches its fulfillment in John the Baptist imprisoned by Herod (Matt 14:3-5) and Paul in Philippian and Roman imprisonment. The imprisoned prophet whose word endures beyond the imprisonment of the prophet is the type of the risen Christ whose resurrection vindicates the word that the crucifixion tried to silence.</p>",
    "26": "<p>A shadow. The prison ration of bread and water — reduced to the minimum — is the economic punishment reserved for political prisoners in the ancient world. For Micaiah, survival on minimum rations pending the king&rsquo;s return is the suffering of the prophet for fidelity to YHWH&rsquo;s word. The bread-and-water reduction points forward to the prison of Joseph (who also received visions and was confined by authority), and ultimately to Christ who &lsquo;suffered outside the gate&rsquo; (Heb 13:12-13) — the excluded one whose execution was the ultimate political silencing of the true witness.</p>",
    "27": "<p>A direct connection. &lsquo;If you return safely, the LORD has not spoken through me&rsquo; — Micaiah stakes his prophetic credibility on the outcome, exactly as Deuteronomy 18:22 requires (&lsquo;if the word does not come to pass or come true, that is a word that the LORD has not spoken&rsquo;). Christ&rsquo;s prophetic credibility was staked on his resurrection: &lsquo;destroy this temple and in three days I will raise it up&rsquo; (John 2:19). The resurrection vindicated the word. &lsquo;All you peoples — take note!&rsquo; Micaiah&rsquo;s call to universal witness anticipates the proclamation to all nations (Matt 28:19-20) of the vindicated true prophet.</p>",
    "28": "<p>A shadow. The joint march on Ramoth-gilead — the covenant king of Judah yoked with the apostate king of Israel — is the shadow of all dangerous alliances that put God&rsquo;s people in harm&rsquo;s way for ungodly causes. The partnership that does not begin with seeking YHWH&rsquo;s word leads into battles YHWH did not sanction. Christ&rsquo;s warning: &lsquo;what fellowship has light with darkness?&rsquo; (2 Cor 6:14) and his prayer &lsquo;I do not ask that you take them out of the world, but that you keep them from the evil one&rsquo; (John 17:15) define the alternative: in the world, but not yoked to the world&rsquo;s battles.</p>",
    "29": "<p>A shadow. Ahab&rsquo;s disguise strategy — going into battle incognito while Jehoshaphat wore royal robes — tried to hide from the divine judgment Micaiah had announced, while putting the innocent Jehoshaphat in greater danger. The attempt to evade prophetic judgment by strategic anonymity shadows every strategy of concealment from YHWH. Heb 4:13: &lsquo;no creature is hidden from his sight, but all are naked and exposed to the eyes of him to whom we must give account.&rsquo; Concealment from human enemies is reasonable; concealment from YHWH&rsquo;s announced judgment is impossible.</p>",
    "30": "<p>A shadow. The Aramean commanders ordered to attack only the king of Israel pass over Jehoshaphat — but at that moment they assume he is that king and turn to attack him. The misdirected attack on the covenant king of Judah because he resembled the doomed king is a shadow of the ways the righteous sometimes suffer from judgments not directed at them. Peter addresses this: &lsquo;if when you do good and suffer for it you endure, this is a gracious thing in the sight of God&rsquo; (1 Pet 2:20). But ultimately, Christ absorbed the blow meant for us — he bore the judgment directed at sinners, taking it on himself (Isa 53:5-6).</p>",
    "31": "<p>A shadow. Jehoshaphat&rsquo;s cry — presumably a prayer to YHWH — and YHWH&rsquo;s response in diverting the chariot commanders away from him is the classic pattern of the cry that averts judgment: &lsquo;they cried to the LORD, and he delivered them out of their distresses&rsquo; (Ps 107:6,13,19,28 — the fourfold rescue pattern of Ps 107). Christ makes the cry effective permanently: his intercession means that all who cry to the Father through him are heard (Heb 7:25: &lsquo;he always lives to make intercession for them&rsquo;). Jehoshaphat&rsquo;s deliverance by his cry foreshadows the permanent deliverance Christ&rsquo;s intercessory cry secures.</p>",
    "32": "<p>A shadow. The chariot commanders recognizing that Jehoshaphat was not the king of Israel and turning away is the providential recognition that spares the innocent. The narrowness of the escape — the commanders were already turning to attack — highlights the thinness of the margin between life and death when covenant people enter battles they were never meant to fight. The reversal (turning away) is YHWH&rsquo;s answer to the cry of v31. The same reversal-of-danger pattern appears in the Red Sea (Exod 14: the pursuing army turned back by the sea), in the Purim reversal (Esth 9:1), and ultimately in the resurrection (death turned back).</p>",
    "33": "<p>A revelation of God. &lsquo;Someone drew his bow without any particular aim (<em>bĕtōm</em>, at random/innocently) and shot the king of Israel between the joints of his armor&rsquo; — the arrow that had no intended target found the one specific opening in the king&rsquo;s disguised armor. This is one of Scripture&rsquo;s most striking pictures of sovereign providence: the &lsquo;random&rsquo; arrow fulfills Micaiah&rsquo;s prophecy and Elijah&rsquo;s oracle against Ahab (1 Kgs 21:19; 22:38). Providence is not the suspension of natural causation but its use by YHWH for specific purposes. Prov 16:33: &lsquo;the lot is cast into the lap, but its every decision is from the LORD.&rsquo; The purposeless arrow reveals the purposeful God.</p>",
    "34": "<p>A shadow. Ahab propped up in his chariot facing the enemy as his life-blood drained away — the dying king maintaining his position until evening — is the shadow of dying royal presence at the battle. It echoes Moses&rsquo; arms held up during the Amalekite battle (Exod 17:12) — the battle goes as the mediating figure stands. More distantly, it points to Christ on the cross &lsquo;facing&rsquo; the cosmic enemies until &lsquo;it was finished&rsquo; (John 19:30). Ahab&rsquo;s propped-up dying is the shadow of the one who remained on the cross until the battle was truly won — not through his military survival but through his willing death.</p>"
  },
  "19": {
    "1": "<p>A theme. Jehoshaphat&rsquo;s safe return to Jerusalem despite his near-fatal involvement in Ahab&rsquo;s doomed battle demonstrates the covenant people&rsquo;s preservation even through their own foolishness. Grace covers not only deliberate sins but also the well-intentioned disasters of covenant people who enter wrong alliances. Paul&rsquo;s principle: &lsquo;where sin increased, grace abounded all the more&rsquo; (Rom 5:20). The return to Jerusalem — to the city of YHWH&rsquo;s house — is always the direction that grace enables; the prodigal son&rsquo;s return is the same movement (Luke 15:20).</p>",
    "2": "<p>A theme. The prophet Jehu&rsquo;s rebuke — &lsquo;Is it right for you to help the wicked and love those who hate the LORD? The wrath of the LORD is on you for this&rsquo; — represents prophetic accountability reaching the covenant king even after his miraculous deliverance. YHWH does not allow sin to pass unaddressed even when he shows mercy. Christ combines both mercies: he addresses sin directly (&lsquo;go and sin no more,&rsquo; John 8:11) while not condemning the sinner. The rebuke that follows mercy is the pastoral-prophetic pattern that Paul calls for in Gal 6:1: &lsquo;restore him in a spirit of gentleness.&rsquo;</p>",
    "3": "<p>A revelation of God. &lsquo;But there is some good in you&rsquo; — the divine assessment that finds and acknowledges genuine faithfulness even within a record of compromise. The seven letters of Revelation 2-3 follow this exact pattern: Christ&rsquo;s evaluation of each church is nuanced, finding what is genuine (&lsquo;I know your works, your toil and your patient endurance,&rsquo; Rev 2:2) before addressing what is deficient. YHWH does not apply a single verdict to a complex life; he discerns the genuine from the counterfeit and honors the genuine even in the context of significant failure. This is the God who did not despise the &lsquo;bruised reed or smoldering wick&rsquo; (Matt 12:20).</p>",
    "4": "<p>A type. Jehoshaphat going out himself among the people to bring them back to YHWH — traveling from Beersheba to the hill country of Ephraim, not sending delegates — is the type of the shepherd-king who personally seeks the lost. The Good Shepherd of John 10:11-14 does not send agents but comes himself; the shepherd in Luke 15:4 leaves the ninety-nine and &lsquo;goes after the lost one until he finds it.&rsquo; The king&rsquo;s personal presence among the people for the purpose of covenant restoration is the royal-pastoral pattern Christ fulfills completely in the incarnation.</p>",
    "5": "<p>A shadow. The appointment of judges throughout the land reflects the principle that YHWH&rsquo;s justice must be locally accessible — not concentrated at the capital only but distributed through the land. The shadow points to Christ&rsquo;s delegation: he sends his disciples to embody kingdom justice throughout the world (Matt 28:18-20; John 20:21: &lsquo;as the Father sent me, even so I am sending you&rsquo;). The judges are not independent authorities but deputies of YHWH&rsquo;s own justice — a distributed network of covenant justice that anticipates the church as the dispersed community of Christ&rsquo;s kingdom.</p>",
    "6": "<p>A direct connection. &lsquo;Be careful what you do, because you are not judging for human beings but for the LORD, who is with you whenever you give a verdict&rsquo; — the principle that all human judgment is conducted in YHWH&rsquo;s immediate presence grounds the NT&rsquo;s repeated insistence on divine impartiality. Acts 10:34: &lsquo;God shows no partiality.&rsquo; Rom 2:2-3: &lsquo;We know that the judgment of God rightly falls on those who practice such things.&rsquo; James 2:1: &lsquo;show no partiality.&rsquo; The reason for human impartiality is always divine impartiality: because the perfectly impartial God is present in judgment, human judges must reflect his character.</p>",
    "7": "<p>A revelation of God. &lsquo;For the LORD our God has no injustice or favoritism or bribery&rsquo; — the absolute moral character of YHWH as the ground of judicial ethics. Paul elaborates: &lsquo;there is no partiality with God&rsquo; (Rom 2:11); &lsquo;with him there is no partiality or regard for position&rsquo; (Eph 6:9); Col 3:25: &lsquo;the wrongdoer will be paid back for the wrong he has done, and there is no partiality.&rsquo; The character of the divine judge is the canon against which all human justice is measured. Christ is the ultimate expression of this character: the one who &lsquo;judges with right judgment&rsquo; (John 7:24) and before whom all must appear (2 Cor 5:10).</p>",
    "8": "<p>A shadow. The Jerusalem court with Levites, priests, and heads of ancestral clans — with Amariah the chief priest having authority over religious cases and Zebadiah over civil-royal cases — reflects the dual structure of priestly and royal jurisdiction in Israel. The shadow points to the Melchizedek figure who unifies both offices: Christ as both priest (Heb 4:14-5:10) and king (Rev 19:16) in his own person collapses the duality that the Jerusalem court maintained by separating the jurisdictions. The high court of heaven has one presiding authority who is both priest and king.</p>",
    "9": "<p>A theme. &lsquo;Carry out your duties in the fear of the LORD, with integrity, and wholeheartedly&rsquo; — the three-part charge to judges: fear (YHWH-orientation), integrity (truth), wholeheartedness (undivided commitment). These are the same three qualities the Chronicler uses to evaluate kings throughout his work. The whole-heart is the Shema quality (Deut 6:5): love YHWH with all your heart. Christ describes the whole-hearted person: &lsquo;blessed are the pure in heart, for they shall see God&rsquo; (Matt 5:8). The pure heart in the judge reflects the heart of the God before whom all judgment takes place.</p>",
    "10": "<p>A shadow. The warning against incurring guilt — &lsquo;otherwise wrath will come upon you and your brothers&rsquo; — frames judicial negligence as a covenant violation that brings collective consequences. The solidarity of the judicial community (your brothers) in the guilt of unjust judgment is the shadow of the community&rsquo;s solidarity in Christ&rsquo;s justification: just as guilt flows from the representative head who fails (Adam, the negligent judge), so righteousness flows from the representative head who succeeds (Christ, the perfectly just judge). Rom 5:18: &lsquo;as one trespass led to condemnation for all men, so one act of righteousness leads to justification and life for all men.&rsquo;</p>",
    "11": "<p>A shadow. The final verse of Jehoshaphat&rsquo;s judicial organization — &lsquo;act courageously and may the LORD be with the good&rsquo; — is the charge to the courts and the priest Amariah and the ruler Zebadiah. The dual authority of priest and prince managing the judicial system shadows the dual office that Christ fills permanently. The Levites appointed as officers (<em>šôṭĕrîm</em>, enforcers/assistants) point toward the apostles whom Christ appoints to carry out his authority in the world (John 20:23: &lsquo;if you forgive the sins of any, they are forgiven them&rsquo;). The organized justice system of Jehoshaphat is a dim reflection of the kingdom of God that Christ administers.</p>"
  },
  "20": {
    "1": "<p>A shadow. The vast coalition — Moabites, Ammonites, and Meunites — assembled against Jehoshaphat mirrors the eschatological pattern of Ps 2:1-2: &lsquo;Why do the nations rage and the peoples plot in vain? The kings of the earth set themselves, and the rulers take counsel together, against the LORD and against his anointed.&rsquo; The gathering of multiple nations against the Davidic king is the recurring OT pattern that culminates in the final gathering against Christ&rsquo;s kingdom (Rev 20:8-9: &lsquo;Gog and Magog, to gather them for battle; their number is like the sand of the sea&rsquo;). What happens in 2 Chr 20 is a historical type of the eschatological war.</p>",
    "2": "<p>A shadow. The threat has already materialized — &lsquo;a vast army is already at En-gedi&rsquo; — before Jehoshaphat even knows about it. The sudden proximity of overwhelming threat is the recurring experience of the covenant people: enemies appear not on the far horizon but at the doorstep. The unexpected-enemy pattern (Haman&rsquo;s decree in Esther; Pharaoh&rsquo;s army at the Red Sea; the angel of death at the first Passover) always resolves into a display of YHWH&rsquo;s power that the threat&rsquo;s very size and suddenness creates the context for. The more overwhelming the threat, the more glorious the deliverance.</p>",
    "3": "<p>A direct connection. &lsquo;Jehoshaphat was alarmed and turned to seek the LORD; he proclaimed a fast for all Judah&rsquo; — the response of fear followed immediately by a turn toward YHWH, expressed in fasting. This is the pattern Christ embodies in Gethsemane: overwhelming threat (the cross) + honest expression of fear (&lsquo;if it is possible, let this cup pass&rsquo;) + complete surrender to the Father (&lsquo;not as I will, but as you will,&rsquo; Matt 26:39). The early church repeated the pattern: when Peter was imprisoned (Acts 12:5), &lsquo;earnest prayer for him was made to God by the church.&rsquo; Fear directed toward YHWH through prayer is the defining covenant response to crisis.</p>",
    "4": "<p>A theme. The corporate gathering of all Judah to seek YHWH — people coming from every town — is the picture of covenant-community prayer at maximum intensity. The corporate dimension is essential: &lsquo;where two or three are gathered in my name, there am I among them&rsquo; (Matt 18:20). The Acts community at Pentecost and in subsequent crises consistently gathers to pray (Acts 1:14; 2:1; 4:24; 12:12). The all-Judah fast-and-prayer assembly shadows the gathered church as the community whose corporate intercession is the means YHWH uses to accomplish his purposes.</p>",
    "5": "<p>A type. Jehoshaphat standing before the congregation in the house of the LORD to intercede is the king as priest — standing before the people to represent them before YHWH, and standing before YHWH to represent the people. This priestly-royal intercessory function is the type of Christ&rsquo;s high-priestly intercession (Heb 7:25: &lsquo;he always lives to make intercession for them&rsquo;). Christ stands in the heavenly sanctuary before the congregation of all his people, making the prayer that Jehoshaphat&rsquo;s prayer foreshadows: &lsquo;Father, save them — the enemy is at the gate.&rsquo;</p>",
    "6": "<p>A revelation of God. &lsquo;LORD, God of our ancestors, you are God in heaven, ruling over all the kingdoms of the nations. Power and might are in your hand, and no one can withstand you&rsquo; — the opening of Jehoshaphat&rsquo;s prayer grounds petition in the universality of YHWH&rsquo;s sovereign reign. The doxological ground of prayer is the divine character: YHWH rules the nations (<em>mālak</em>), power and might are in his hand, and no one stands against him. Jesus&rsquo; Lord&rsquo;s Prayer begins the same way: &lsquo;Our Father in heaven, hallowed be your name, your kingdom come&rsquo; (Matt 6:9-10). The kingdom&rsquo;s universal sovereignty is the ground on which all petition rests.</p>",
    "7": "<p>A direct connection. &lsquo;Our God, you drove out the inhabitants of this land before your people Israel and gave it forever to the descendants of your friend Abraham&rsquo; — the Abrahamic covenant as the ground of petition. Paul directly applies the Abrahamic promise to Christ: &lsquo;the promises were made to Abraham and to his offspring. It does not say, &ldquo;And to offsprings,&rdquo; referring to many, but referring to one, &ldquo;And to your offspring,&rdquo; who is Christ&rsquo; (Gal 3:16). The &lsquo;forever to the descendants of your friend Abraham&rsquo; is ultimately secured not in land-tenure but in Christ, Abraham&rsquo;s singular seed, through whom all Abraham&rsquo;s heirs receive the inheritance (Gal 3:29).</p>",
    "8": "<p>A shadow. &lsquo;They have lived in it and have built in it a sanctuary for your name, saying&rsquo; — the inhabiting and building by the covenant community is the shadow of the church as the new temple. 1 Cor 3:16: &lsquo;do you not know that you are God&rsquo;s temple and that God&rsquo;s Spirit dwells in you?&rsquo; 1 Pet 2:5: &lsquo;you yourselves like living stones are being built up as a spiritual house.&rsquo; The physical sanctuary Israel built in the land foreshadows the community-sanctuary that Christ builds — a living temple not of stone but of people inhabited by the Spirit.</p>",
    "9": "<p>A direct connection. &lsquo;When calamity strikes us... we will stand before this house and before you... and cry out to you in our distress, and you will hear and save&rsquo; — Jehoshaphat&rsquo;s prayer explicitly invokes Solomon&rsquo;s dedicatory prayer (2 Chr 6:28-31). The temple as the place where crisis-prayer is directed becomes, in Christ, the person of Christ himself: &lsquo;whatever you ask in my name, this I will do, that the Father may be glorified in the Son&rsquo; (John 14:13). The temple orientation of Jehoshaphat&rsquo;s prayer is fulfilled when Jesus declares himself the new temple (John 2:19-21) — prayer directed toward Christ is now directed toward the ultimate meeting-place of God and humanity.</p>",
    "10": "<p>A shadow. Jehoshaphat&rsquo;s appeal to YHWH&rsquo;s own history — YHWH commanded Israel not to invade Ammon, Moab, and Seir (Deut 2:4-9,19), so Israel spared them, and now those same nations invade — is a prayer argument from covenant consistency: &lsquo;YHWH, your own mercy established their presence here; their ingratitude is an insult to your mercy.&rsquo; Paul makes the same argument for Gentile salvation: YHWH&rsquo;s mercy to Gentiles (attested throughout the OT) is the precedent for their full inclusion in Christ (Rom 15:9-12). The very nations that were spared by YHWH&rsquo;s covenant mercy are invited into the covenant blessing through Christ.</p>",
    "11": "<p>A shadow. &lsquo;See how they repay us by coming to drive us out of your land which you gave us&rsquo; — the ingratitude of the nations who benefited from YHWH&rsquo;s mercy but now use their preserved existence to attack his people is the mirror of the ingratitude Jesus describes in the parable of the unforgiving servant (Matt 18:23-35): the servant forgiven an enormous debt refuses to forgive a small debt owed to him. The covenant logic Jehoshaphat appeals to is the same: YHWH&rsquo;s mercy to the nations creates an obligation of non-hostility toward the covenant community that Ammon and Moab have violated.</p>",
    "12": "<p>A direct connection. &lsquo;Our God, will you not judge them? We are powerless against this vast army attacking us. We do not know what to do, but our eyes are on you&rsquo; — the prayer of complete helplessness directed entirely toward YHWH is one of Scripture&rsquo;s most arresting moments of faith. It perfectly anticipates Gethsemane: &lsquo;Abba, Father, all things are possible for you. Remove this cup from me. Yet not what I will, but what you will&rsquo; (Mark 14:36). The &lsquo;I do not know what to do&rsquo; of Jehoshaphat and the &lsquo;not what I will&rsquo; of Gethsemane are both the complete surrender of human agency to divine sovereignty. This is the prayer the Father always hears.</p>",
    "13": "<p>A theme. All the people of Judah standing before YHWH — including the little ones, the wives, and the children — is the whole-community assembly of covenant prayer. The inclusion of children in the covenant assembly mirrors the community-wide Passover, the Sukkot celebration, and the covenant-renewal assemblies. Pentecost gathered &lsquo;all together in one place&rsquo; (Acts 2:1); the vision of universal worship in Revelation includes &lsquo;every tribe, language, people, and nation&rsquo; (Rev 5:9). The inclusion of the vulnerable (children) in the crisis-prayer assembly is the covenant community&rsquo;s instinct that every member of the covenant bears equal standing before YHWH.</p>",
    "14": "<p>A direct connection. &lsquo;The Spirit of the LORD came on Jahaziel&rsquo; — the Spirit&rsquo;s sudden initiative in the midst of the congregation, giving the war-oracle, is the precedent for Pentecost: &lsquo;suddenly there came from heaven a sound like a mighty rushing wind, and it filled the entire house... and they were all filled with the Holy Spirit and began to speak in other tongues as the Spirit gave them utterance&rsquo; (Acts 2:2-4). The Spirit who spoke through Jahaziel to give the battle-oracle speaks through the apostolic community to announce the victory of the risen Christ. Both oracles are spoken to a people facing an impossible situation and needing divine assurance.</p>",
    "15": "<p>A direct connection. &lsquo;Do not be afraid or discouraged because of this vast army, for the battle is not yours but God&rsquo;s&rsquo; — this oracle is one of the OT&rsquo;s most direct anticipations of the NT&rsquo;s theology of divine victory in human weakness. John 16:33: &lsquo;in the world you will have tribulation, but take heart; I have overcome the world.&rsquo; The battle belongs to God; the disciples participate in a victory already won by Christ&rsquo;s cross and resurrection. Col 2:15: &lsquo;he disarmed the rulers and authorities and put them to open shame, by triumphing over them in him.&rsquo; The war is over; the people of God stand in the territory of the victor.</p>",
    "16": "<p>A shadow. The oracle&rsquo;s specific tactical direction — &lsquo;tomorrow march down... you will find them at the end of the ravine before the wilderness of Jeruel&rsquo; — is the specificity of divine guidance: not general encouragement but precise direction for the next step. Jesus&rsquo; guidance of his disciples was similarly specific: he told them where to find the colt (Mark 11:2), who would offer the Passover room (Mark 14:13-15), where the fish would be (Luke 5:4; John 21:6). The God who sees the end from the beginning gives specific instruction to those who trust him — the oracle&rsquo;s specificity is evidence of divine knowledge that no human intelligence could provide.</p>",
    "17": "<p>A direct connection. &lsquo;You will not need to fight in this battle. Take your positions, stand firm, and watch the LORD save you&rsquo; — the &lsquo;stand firm&rsquo; command is the NT&rsquo;s spiritual-warfare posture: &lsquo;put on the whole armor of God, that you may be able to stand against the schemes of the devil... and having done all, stand firm&rsquo; (Eph 6:11,13-14). 1 Cor 15:58: &lsquo;be steadfast, immovable, always abounding in the work of the Lord.&rsquo; The command not to fight but to stand and watch is the counter-intuitive warfare principle of the kingdom: the decisive battle was fought by another; the people&rsquo;s role is to stand in the victory he won.</p>",
    "18": "<p>A type. Jehoshaphat&rsquo;s prostration — bowing with his face to the ground — and all Judah&rsquo;s worship before YHWH is the community&rsquo;s response to the divine oracle: they worship before moving. Worship precedes action. The risen Christ&rsquo;s disciples worshiped before receiving the commission (Matt 28:17: &lsquo;when they saw him they worshiped him&rsquo; — then the Great Commission). Pentecost occurred among praying worshipers (Acts 1:14). The order — oracle, worship, action — is the order Christ&rsquo;s followers are meant to maintain: hear, adore, then move.</p>",
    "19": "<p>A theme. The Levitical singers standing and praising &lsquo;with a very loud voice&rsquo; — before the battle, the night before the march — is the praise that precedes the deliverance. The pattern: praise → divine action, not divine action → praise (though that is also right). The early church maintained this order: &lsquo;About midnight Paul and Silas were praying and singing hymns to God, and the prisoners were listening to them, and suddenly there was a great earthquake&rsquo; (Acts 16:25-26). The praise at midnight, the praise before the battle, is the faith that God honors with earthquake-level intervention.</p>",
    "20": "<p>A direct connection. &lsquo;Trust in the LORD your God and you will stand firm; trust in his prophets and you will prosper&rsquo; — the double trust-command (trust YHWH, trust his appointed messengers) is the OT&rsquo;s clearest statement of the connection between faith and standing. Jesus expands: &lsquo;believe in God; believe also in me&rsquo; (John 14:1). The prophet&rsquo;s word and the divine word are coordinated: faith in the messenger is faith in the one who sent the messenger. The NT apostolic principle follows: believing the apostolic word is believing Christ (John 17:20: &lsquo;those who will believe in me through their word&rsquo;). Trust in the prophetic word produces standing firm.</p>",
    "21": "<p>A type. The appointment of singers to walk before the army, singing &lsquo;Give thanks to the LORD, for his love endures forever&rsquo; — the praise-army that leads the military deployment — is one of the Bible&rsquo;s most striking types of kingdom warfare. Praise as the weapon and the vanguard — not swords and shields but the liturgical formula of thanksgiving — is the type of the cross: &lsquo;the word of the cross is folly to those who are perishing, but to us who are being saved it is the power of God&rsquo; (1 Cor 1:18). The song that appears to be weakness is in fact the divine ambush being set. Christ&rsquo;s own song was sung in death (Ps 22:1, quoted from the cross) before the resurrection victory.</p>",
    "22": "<p>A direct connection. &lsquo;As they began to sing and praise, the LORD set an ambush against the men of Ammon, Moab, and Mount Seir&rsquo; — the divine ambush triggered by human praise is the paradigm of spiritual warfare in Christ: the cross appeared to be defeat but was the divine trap that disarmed the principalities. 1 Cor 2:7-8: &lsquo;we impart a secret and hidden wisdom of God... which none of the rulers of this age understood, for if they had, they would not have crucified the Lord of glory.&rsquo; The rulers who crucified Christ sprung the divine ambush against themselves. Paul makes the identical structural point in Col 2:15: &lsquo;he disarmed the rulers and authorities and put them to open shame, triumphing over them in him&rsquo; — at the cross, the apparent defeat was YHWH&rsquo;s ambush.</p>",
    "23": "<p>A shadow. The coalition turns on itself — Ammon and Moab attack Mount Seir, then turn on each other — without any Judahite combat. The enemy self-destruction triggered by divine intervention is the type of the eschatological coalition&rsquo;s internal collapse: &lsquo;on that day every man&rsquo;s sword will be against his brother&rsquo; (Ezek 38:21); Rev 17:16-17 (the beast and the prostitute destroy each other in the final conflict). The coalition that gathered against YHWH&rsquo;s anointed cannot maintain its unity; the very diversity that made it threatening becomes the mechanism of its self-destruction.</p>",
    "24": "<p>A shadow. When Judah reaches the watchtower and looks toward the enemy — &lsquo;they were corpses lying on the ground; none had escaped&rsquo; — the battle is already over before they arrive. The covenant people arrive to find an already-accomplished victory: their role was to show up in faith, not to fight the battle. This is precisely the resurrection dynamic: the disciples arrive at the tomb (Matt 28:1; John 20:1) to find the battle already won. The stone is rolled away, the tomb is empty, the enemy is defeated. The watchtower view of Judah — utter and complete destruction with none remaining — is the type of the empty tomb.</p>",
    "25": "<p>A shadow. The three days of plunder-collection — goods, clothing, and articles &lsquo;more than they could carry&rsquo; — is a shadow of the overflowing abundance that results from divine victory. The plunder that exceeds the capacity of the victors to carry anticipates the eschatological abundance: Rev 21:24-26 (the kings of the earth bring their glory and honor into the new Jerusalem). The covenant people who cannot carry all the spoils of YHWH&rsquo;s war shadows the inheritance that &lsquo;surpasses knowledge&rsquo; (Eph 3:19) — the riches of Christ that exceed all that could be asked or imagined.</p>",
    "26": "<p>A theme. The Valley of Berachah (Blessing) — named at the moment of corporate thanksgiving on the fourth day — is the place of battle renamed as the place of blessing. The valley of crisis becomes the valley of testimony. This is the pattern of every testimony: the Jordan becomes a crossing-point (Josh 3), the wilderness becomes the place of provision (Exod 16), the cross becomes the place of resurrection. Christ names the blessing he will bring to the places of trial: &lsquo;blessed are those who mourn, for they shall be comforted; blessed are the meek, for they shall inherit the earth&rsquo; (Matt 5:4-5). The valley of weeping becomes a place of springs (Ps 84:6).</p>",
    "27": "<p>A type. The return to Jerusalem with Jehoshaphat leading, &lsquo;for the LORD had given them cause to rejoice over their enemies&rsquo; — the triumphal return of the covenant community behind their king — is the type of the church&rsquo;s triumph behind the risen Christ. Col 2:15: Christ &lsquo;triumphing over them in him.&rsquo; Rev 19:14: &lsquo;the armies of heaven, arrayed in fine white linen, were following him.&rsquo; The community that followed the singers into battle now follows the victorious king home — the processional victory that Jehoshaphat leads is the type of the final triumphal return of the church behind the conquering Lamb.</p>",
    "28": "<p>A theme. The arrival at the house of the LORD with lyres, harps, and trumpets — the full worship ensemble — frames the military victory within the liturgical context. The battle was a worship event; the return is a worship event. The same instruments appear in the heavenly worship of Revelation (Rev 5:8: golden bowls and harps; 8:2: seven trumpets; 14:2: harps). The church that worships before the battle (v18-19), during the battle (v21-22), and after the battle (v28) has understood that all of life is liturgy — warfare is worship and worship is warfare.</p>",
    "29": "<p>A theme. The terror of God falling on surrounding kingdoms when they heard that YHWH fought against Israel&rsquo;s enemies is the missiological side-effect of covenant warfare: the fear that silences the nations. Acts 2:43: &lsquo;awe came upon every soul.&rsquo; Acts 19:17: &lsquo;fear fell on them all, and the name of the Lord Jesus was extolled.&rsquo; The mission strategy of the early church was not primarily intimidation but the overspill of divine power — the surrounding world watched what God did for the covenant community and was either drawn in wonder or paralyzed in fear. The terror of YHWH is the precondition for the fear that leads to seeking (Ps 76:11).</p>",
    "30": "<p>A shadow. &lsquo;The kingdom was at peace, for his God gave him rest on every side&rsquo; — the Sabbath-rest formula for the completed victory. The same formula is used for Solomon&rsquo;s kingdom (2 Chr 1:1; 1 Kgs 4:24-25) and for the conquest period (Josh 23:1: &lsquo;the LORD had given Israel rest from all their surrounding enemies&rsquo;). The Chronicler&rsquo;s post-exilic audience, living in a land not yet at full rest, heard this as eschatological promise. Heb 4:9-10: &lsquo;there remains a Sabbath rest for the people of God, for whoever has entered God&rsquo;s rest has also rested from his works as God did from his.&rsquo; The rest given by Jehoshaphat&rsquo;s God is the shadow of the eternal rest Christ secures.</p>",
    "31": "<p>A shadow. The summary of Jehoshaphat&rsquo;s reign — thirty-five years old at accession, twenty-five years of reign — and the mother&rsquo;s name (Azubah daughter of Shilhi) is the covenant context within which the theological themes of chs 18-20 were lived out. The king&rsquo;s humanity (a specific age, a specific mother, a specific length of reign) grounds the theological drama in historical reality. Christ&rsquo;s humanity is similarly specific: born in Bethlehem, in the days of Herod, approximately 4-6 BCE. The theological significance of the king&rsquo;s reign is not diminished by its specific human particularity — it is the specific human particularity that makes the theology real.</p>",
    "32": "<p>A shadow. &lsquo;He followed the example of his father Asa and did not deviate from it, doing what was right in the LORD&rsquo;s eyes&rsquo; — the chain of covenant inheritance across generations. The Davidic line at its best is a chain of covenant imitation: son following father following grandfather, each walking in the ways of the one who walked with YHWH. The chain is broken by sin and restored by repentance in each generation. Christ is the final link and the fulfillment of the chain: &lsquo;Long ago... he spoke to our fathers by the prophets, but in these last days he has spoken to us by his Son&rsquo; (Heb 1:1-2). The accumulated covenant faithfulness of Asa → Jehoshaphat is the shadow of the Son who perfectly fulfills what every faithful king partly realized.</p>",
    "33": "<p>A shadow. &lsquo;The high places were not removed, and the people still had not fully committed their hearts to the God of their ancestors&rsquo; — the incomplete reformation even under the best king. Even Jehoshaphat, whose extraordinary victory fills ch 20, could not produce the full-heart reformation that the Deuteronomic ideal required. This incompleteness is the OT&rsquo;s persistent testimony to the inadequacy of human covenant faithfulness, however sincere. Jer 31:33: &lsquo;I will put my law within them, and I will write it on their hearts.&rsquo; The new covenant that writes the law on the heart — not merely on stone or in memory — is the answer to the persistent &lsquo;hearts not fully committed.&rsquo; Christ is the mediator of this covenant (Heb 9:15).</p>",
    "34": "<p>A shadow. The additional records of Jehoshaphat&rsquo;s acts — written in the account of Jehu son of Hanani, which was incorporated into the book of the kings of Israel — point to the Chronicler&rsquo;s use of earlier prophetic sources. The king&rsquo;s full life is more than any single record contains. This shadow points to John 21:25: &lsquo;were every one of them to be written, I suppose that the world itself could not contain the books that would be written&rsquo; about what Jesus did. The written record of the king&rsquo;s life is necessarily selective; the fullness exceeds the record. Christ&rsquo;s life, works, and significance infinitely exceed what the Gospels record.</p>",
    "35": "<p>A shadow. Jehoshaphat&rsquo;s alliance with Ahaziah of Israel — the wicked king, son of Ahab — is the second ungodly alliance in Jehoshaphat&rsquo;s reign (the first was with Ahab, ch 18), demonstrating that the pattern of compromise was a persistent character weakness even in a generally faithful king. The good king who keeps making the same type of mistake — allying with the ungodly — is the shadow of the warning Peter gives: &lsquo;your adversary the devil prowls around like a roaring lion... resist him, firm in your faith&rsquo; (1 Pet 5:8-9). The enemy targets the pattern of weakness repeatedly. Christ is the one who was &lsquo;in every respect tempted as we are, yet without sin&rsquo; (Heb 4:15) — the alliance-temptation was resisted perfectly.</p>",
    "36": "<p>A shadow. The joint shipbuilding venture at Ezion-geber for Tarshish-bound ships represents commercial partnership with the ungodly — Solomon had also used Ezion-geber for his maritime trade (2 Chr 8:17-18) but in partnership with Huram of Tyre, whose acknowledgment of YHWH is noted (2 Chr 2:12). Ahaziah&rsquo;s partnership is a different category — joining a man characterized by wickedness. The commercial-spiritual alliance is the shadow of the NT warning about business partnerships that compromise covenant values (2 Cor 6:14-15: &lsquo;do not be unequally yoked with unbelievers... what partnership has righteousness with lawlessness?&rsquo;).</p>",
    "37": "<p>A shadow. Eliezer&rsquo;s prophecy against Jehoshaphat — &lsquo;because you allied with Ahaziah, the LORD has broken apart what you made&rsquo; — and the ships that broke up so they could not sail to Tarshish demonstrates the principle that YHWH&rsquo;s covenant discipline follows the second alliance as surely as it followed the first. The covenant protection that delivered Jehoshaphat from Ahab&rsquo;s battle is not a blank check for future compromise. Grace does not eliminate consequences; it restores relationship after consequences. Christ&rsquo;s word to the woman taken in adultery — &lsquo;neither do I condemn you; go and sin no more&rsquo; (John 8:11) — holds both dimensions: mercy without condemnation AND the call to a different direction.</p>"
  }
}

def main():
    existing = load_comm('mkt-christ', '2chronicles')
    merge_comm(existing, CHRIST)
    save_comm('mkt-christ', '2chronicles', existing)
    total = sum(len(vv) for vv in CHRIST.values())
    print(f'2Chronicles 18-20 mkt-christ written ({total} verses across 3 chapters).')

if __name__ == '__main__':
    main()
